        CountDownLatch ready,
        CountDownLatch release
    ) throws Exception {
        ready.countDown();
        if (!release.await(5, TimeUnit.SECONDS)) {
            throw new IllegalStateException("Request release timed out");
        }

        WorkerHandle binding = ThreadBridge.current(revisions);
        return binding.process(record);
    }

    @Override
    public void close() throws Exception {
        revisions.close();
        List<Future<?>> cleanups = new ArrayList<>();
        for (int i = 0; i < workerCount; i++) {
            cleanups.add(workers.submit(ThreadBridge::clear));
        }
        for (Future<?> cleanup : cleanups) {
            cleanup.get(5, TimeUnit.SECONDS);
        }
        revisions.isBalanced();
        workers.shutdown();
        workers.awaitTermination(5, TimeUnit.SECONDS);
    }

    private static final class WorkerThreadFactory implements ThreadFactory {
        private final AtomicInteger sequence = new AtomicInteger(1);

        @Override
        public Thread newThread(Runnable runnable) {
            Thread thread = new Thread(runnable);
            thread.setName("textd-worker-" + sequence.getAndIncrement());
            thread.setDaemon(true);
            return thread;
        }
    }
}
